// src/index.js
import React from 'react';
import ReactDOM from 'react-dom/client';
import './index.css';
import App from './App';

// Optional: only in development – helps catch bugs early
const isDevelopment = process.env.NODE_ENV === 'development';

const rootElement = document.getElementById('root');

if (rootElement) {
  const root = ReactDOM.createRoot(rootElement);

  // Apply dark mode class to html element (for Tailwind dark: prefix)
  document.documentElement.classList.add('dark');

  root.render(
    <>
      {/* StrictMode only in development – removes double renders in prod */}
      {isDevelopment ? (
        <React.StrictMode>
          <App />
        </React.StrictMode>
      ) : (
        <App />
      )}
    </>
  );
} else {
  console.error('Root element not found – check public/index.html for <div id="root"></div>');
}

// Optional: simple global error boundary (shows friendly message in dev)
if (isDevelopment) {
  window.addEventListener('error', (event) => {
    console.error('Global uncaught error:', event.error);
    // You can show a UI overlay here if you want
  });
}

// Optional: remove or comment out if you don't use performance monitoring
// reportWebVitals(console.log);
